#include <vector>
#include <algorithm>

using namespace std;

vector<vector<long long>> solve(vector<vector<long long>> grid, long long x, long long y, long long k) {
    vector<vector<long long>> newGrid = grid;
    vector<vector<long long>> subRows;

    for (int i = 0; i < k; ++i) {
        vector<long long> row(newGrid[x + i].begin() + y, newGrid[x + i].begin() + y + k);
        subRows.push_back(row);
    }

    reverse(subRows.begin(), subRows.end());

    for (int i = 0; i < k; ++i) {
        for (int j = 0; j < k; ++j) {
            newGrid[x + i][y + j] = subRows[i][j];
        }
    }

    return newGrid;
}
```

